import{_ as s,o as a,c as i,ai as o}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Model Failover","description":"","frontmatter":{"summary":"How OpenSoul rotates auth profiles and falls back across models","read_when":["Diagnosing auth profile rotation, cooldowns, or model fallback behavior","Updating failover rules for auth profiles or models"],"title":"Model Failover"},"headers":[],"relativePath":"concepts/model-failover.md","filePath":"concepts/model-failover.md","lastUpdated":null}'),l={name:"concepts/model-failover.md"};function n(t,e,r,d,p,h){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="model-failover" tabindex="-1"><a class="header-anchor" href="#model-failover">#</a> Model failover</h1><p>OpenSoul handles failures in two stages:</p><ol><li><strong>Auth profile rotation</strong> within the current provider.</li><li><strong>Model fallback</strong> to the next model in <code>agents.defaults.model.fallbacks</code>.</li></ol><p>This doc explains the runtime rules and the data that backs them.</p><h2 id="auth-storage-keys-oauth" tabindex="-1"><a class="header-anchor" href="#auth-storage-keys-oauth">#</a> Auth storage (keys + OAuth)</h2><p>OpenSoul uses <strong>auth profiles</strong> for both API keys and OAuth tokens.</p><ul><li>Secrets live in <code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth-profiles.json</code> (legacy: <code>~/.opensoul/agent/auth-profiles.json</code>).</li><li>Config <code>auth.profiles</code> / <code>auth.order</code> are <strong>metadata + routing only</strong> (no secrets).</li><li>Legacy import-only OAuth file: <code>~/.opensoul/credentials/oauth.json</code> (imported into <code>auth-profiles.json</code> on first use).</li></ul><p>More detail: <a href="/docs/concepts/oauth">/concepts/oauth</a></p><p>Credential types:</p><ul><li><code>type: &quot;api_key&quot;</code> → <code>{ provider, key }</code></li><li><code>type: &quot;oauth&quot;</code> → <code>{ provider, access, refresh, expires, email? }</code> (+ <code>projectId</code>/<code>enterpriseUrl</code> for some providers)</li></ul><h2 id="profile-ids" tabindex="-1"><a class="header-anchor" href="#profile-ids">#</a> Profile IDs</h2><p>OAuth logins create distinct profiles so multiple accounts can coexist.</p><ul><li>Default: <code>provider:default</code> when no email is available.</li><li>OAuth with email: <code>provider:&lt;email&gt;</code> (for example <code>google-antigravity:user@gmail.com</code>).</li></ul><p>Profiles live in <code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth-profiles.json</code> under <code>profiles</code>.</p><h2 id="rotation-order" tabindex="-1"><a class="header-anchor" href="#rotation-order">#</a> Rotation order</h2><p>When a provider has multiple profiles, OpenSoul chooses an order like this:</p><ol><li><strong>Explicit config</strong>: <code>auth.order[provider]</code> (if set).</li><li><strong>Configured profiles</strong>: <code>auth.profiles</code> filtered by provider.</li><li><strong>Stored profiles</strong>: entries in <code>auth-profiles.json</code> for the provider.</li></ol><p>If no explicit order is configured, OpenSoul uses a round‑robin order:</p><ul><li><strong>Primary key:</strong> profile type (<strong>OAuth before API keys</strong>).</li><li><strong>Secondary key:</strong> <code>usageStats.lastUsed</code> (oldest first, within each type).</li><li><strong>Cooldown/disabled profiles</strong> are moved to the end, ordered by soonest expiry.</li></ul><h3 id="session-stickiness-cache-friendly" tabindex="-1"><a class="header-anchor" href="#session-stickiness-cache-friendly">#</a> Session stickiness (cache-friendly)</h3><p>OpenSoul <strong>pins the chosen auth profile per session</strong> to keep provider caches warm. It does <strong>not</strong> rotate on every request. The pinned profile is reused until:</p><ul><li>the session is reset (<code>/new</code> / <code>/reset</code>)</li><li>a compaction completes (compaction count increments)</li><li>the profile is in cooldown/disabled</li></ul><p>Manual selection via <code>/model …@&lt;profileId&gt;</code> sets a <strong>user override</strong> for that session and is not auto‑rotated until a new session starts.</p><p>Auto‑pinned profiles (selected by the session router) are treated as a <strong>preference</strong>: they are tried first, but OpenSoul may rotate to another profile on rate limits/timeouts. User‑pinned profiles stay locked to that profile; if it fails and model fallbacks are configured, OpenSoul moves to the next model instead of switching profiles.</p><h3 id="why-oauth-can-look-lost" tabindex="-1"><a class="header-anchor" href="#why-oauth-can-look-lost">#</a> Why OAuth can “look lost”</h3><p>If you have both an OAuth profile and an API key profile for the same provider, round‑robin can switch between them across messages unless pinned. To force a single profile:</p><ul><li>Pin with <code>auth.order[provider] = [&quot;provider:profileId&quot;]</code>, or</li><li>Use a per-session override via <code>/model …</code> with a profile override (when supported by your UI/chat surface).</li></ul><h2 id="cooldowns" tabindex="-1"><a class="header-anchor" href="#cooldowns">#</a> Cooldowns</h2><p>When a profile fails due to auth/rate‑limit errors (or a timeout that looks like rate limiting), OpenSoul marks it in cooldown and moves to the next profile. Format/invalid‑request errors (for example Cloud Code Assist tool call ID validation failures) are treated as failover‑worthy and use the same cooldowns.</p><p>Cooldowns use exponential backoff:</p><ul><li>1 minute</li><li>5 minutes</li><li>25 minutes</li><li>1 hour (cap)</li></ul><p>State is stored in <code>auth-profiles.json</code> under <code>usageStats</code>:</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;usageStats&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;provider:profile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;lastUsed&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1736160000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;cooldownUntil&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1736160600000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;errorCount&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="billing-disables" tabindex="-1"><a class="header-anchor" href="#billing-disables">#</a> Billing disables</h2><p>Billing/credit failures (for example “insufficient credits” / “credit balance too low”) are treated as failover‑worthy, but they’re usually not transient. Instead of a short cooldown, OpenSoul marks the profile as <strong>disabled</strong> (with a longer backoff) and rotates to the next profile/provider.</p><p>State is stored in <code>auth-profiles.json</code>:</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;usageStats&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;provider:profile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;disabledUntil&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1736178000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;disabledReason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;billing&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>Defaults:</p><ul><li>Billing backoff starts at <strong>5 hours</strong>, doubles per billing failure, and caps at <strong>24 hours</strong>.</li><li>Backoff counters reset if the profile hasn’t failed for <strong>24 hours</strong> (configurable).</li></ul><h2 id="model-fallback" tabindex="-1"><a class="header-anchor" href="#model-fallback">#</a> Model fallback</h2><p>If all profiles for a provider fail, OpenSoul moves to the next model in <code>agents.defaults.model.fallbacks</code>. This applies to auth failures, rate limits, and timeouts that exhausted profile rotation (other errors do not advance fallback).</p><p>When a run starts with a model override (hooks or CLI), fallbacks still end at <code>agents.defaults.model.primary</code> after trying any configured fallbacks.</p><h2 id="related-config" tabindex="-1"><a class="header-anchor" href="#related-config">#</a> Related config</h2><p>See <a href="/docs/gateway/configuration">Gateway configuration</a> for:</p><ul><li><code>auth.profiles</code> / <code>auth.order</code></li><li><code>auth.cooldowns.billingBackoffHours</code> / <code>auth.cooldowns.billingBackoffHoursByProvider</code></li><li><code>auth.cooldowns.billingMaxHours</code> / <code>auth.cooldowns.failureWindowHours</code></li><li><code>agents.defaults.model.primary</code> / <code>agents.defaults.model.fallbacks</code></li><li><code>agents.defaults.imageModel</code> routing</li></ul><p>See <a href="/docs/concepts/models">Models</a> for the broader model selection and fallback overview.</p>`,46)])])}const f=s(l,[["render",n]]);export{u as __pageData,f as default};
